content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kě yǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "可以幫我加珍珠嗎？",
      "pinyin": "Kě yǐ bāng wǒ jiā zhēn zhū ma?",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0?",
      "translation_en": "Can you add boba for me?",
      "translation_ko": "타피오카 펄을 추가해 주실 수 있나요?"
    },
    {
      "text": "我想要一杯紅茶，半糖，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi hóng chá, bàn táng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 hong2 cha2, ban4 tang2, ke3 yi3 ma0?",
      "translation_en": "I would like a cup of black tea, half sugar, okay?",
      "translation_ko": "홍차 한 잔, 반 당으로 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以給我一個袋子嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ gěi wǒ yī gè dài zi ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ke3 yi3 gei3 wo3 yi1 ge4 dai4 zi0 ma0?",
      "translation_en": "Excuse me, can you give me a bag?",
      "translation_ko": "실례합니다, 봉투 하나 주실 수 있나요?"
    },
    {
      "text": "請問，這個價錢可以嗎？",
      "pinyin": "Qǐng wèn, zhè ge jià qián kě yǐ ma?",
      "pinyin_numeric": "qing3 wen4, zhe4 ge5 jia4 qian2 ke3 yi3 ma0?",
      "translation_en": "Excuse me, is this price okay?",
      "translation_ko": "실례합니다, 이 가격이 괜찮나요?"
    },
    {
      "text": "可以幫我外帶嗎？",
      "pinyin": "Kě yǐ bāng wǒ wài dài ma?",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 wai4 dai4 ma0?",
      "translation_en": "Can you make it for takeout?",
      "translation_ko": "포장해 주실 수 있나요?"
    },
    {
      "text": "我想要一杯綠茶，去冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi lǜ chá, qù bīng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 lü4 cha2, qu4 bing1, ke3 yi3 ma0?",
      "translation_en": "I would like a cup of green tea, no ice, okay?",
      "translation_ko": "녹차 한 잔, 얼음 없이 주실 수 있나요?"
    },
    {
      "text": "麻煩你，可以給我一根吸管嗎？",
      "pinyin": "Má fan nǐ, kě yǐ gěi wǒ yī gēn xī guǎn ma?",
      "pinyin_numeric": "ma2 fan0 ni3, ke3 yi3 gei3 wo3 yi1 gen1 xi1 guan3 ma0?",
      "translation_en": "Excuse me, can you give me a straw?",
      "translation_ko": "번거롭게 해서 죄송합니다만, 빨대 하나 주실 수 있나요?"
    },
    {
      "text": "可以等一下嗎？我還要再想一下。",
      "pinyin": "Kě yǐ děng yī xià ma? Wǒ hái yào zài xiǎng yī xià.",
      "pinyin_numeric": "ke3 yi3 deng3 yi1 xia4 ma0? wo3 hai2 yao4 zai4 xiang3 yi1 xia4.",
      "translation_en": "Can you wait a moment? I need to think a bit more.",
      "translation_ko": "잠시 기다려 주실 수 있나요? 좀 더 생각해 봐야 해요."
    },
    {
      "text": "不好意思，可以再說一次嗎？慢一點。",
      "pinyin": "Bù hǎo yì si, kě yǐ zài shuō yī cì ma? Màn yī diǎn.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ke3 yi3 zai4 shuo1 yi1 ci4 ma0? man4 yi1 dian3.",
      "translation_en": "Excuse me, can you say it again? Slower.",
      "translation_ko": "실례합니다, 한 번 더 말씀해 주시겠어요? 조금 천천히요."
    }
  ]
}
